"""
mkt-original | ruth | ch 1-4 gap-fill (65 missing verses)
Ruth: hesed (lovingkindness), goel (kinsman-redeemer), return/shuv,
menucha (rest), kanaf (wing/skirt), shem (name/legacy), gleaning law.
Run: python3 scripts/zc-original-ruth-1-4-fill.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

RUTH = {
  "1": {
    "3": "<p><strong>vayyamot elimelech ish naomi</strong>: 'Then Elimelech, Naomi's husband, died.' The opening movement of Ruth is a series of deaths: Elimelech (v3), then both sons Mahlon and Chilion (v5). The triple bereavement strips Naomi of every male protector and provider in the patriarchal economy. <em>Elimelech</em> ('my God is king') dies first — the man whose name proclaimed divine sovereignty goes first, leaving the women in a godless economy. The theological irony is deliberate: when 'my God is king' is gone, what remains? The book will answer: <em>chesed</em> (steadfast love), expressed through a Moabite widow and a redeemer kinsman.</p>",
    "4": "<p><strong>vayisu lahem nashim moaviyot</strong>: 'they took Moabite women as wives.' The sons marry outside Israel — a detail the narrator mentions without editorial judgment. <em>Orpah</em> (possibly from <em>oref</em>, neck/back — later she turns her back) and <em>Ruth</em> (possibly from <em>reut</em>, friendship/companionship, or from the root <em>rvh</em>, to be satisfied) bear names whose meanings become narratively significant. The Moabite origin matters because Ruth's loyalty will explicitly transcend the ethnic boundary her name marks: a Moabitess who becomes the model of <em>chesed</em> is the book's reversal of category expectations.</p>",
    "5": "<p><strong>vatishshaer ha-isha mishney yeladeiha ume-ishah</strong>: 'she was left without (<em>vatishshaer</em>, was remaining) her two sons and her husband.' The root <em>sh-'-r</em> (to remain, be left over) is the remnant word — the same root as <em>she'erit</em> (remnant) in prophetic literature. Naomi is the survivor, the remnant of her household. The phrase structurally echoes Job 1:15-19, where messenger after messenger says 'I alone have escaped to tell you' (<em>va'imalletah rak ani levaddi</em>). Both texts frame radical loss as the theological starting condition from which YHWH will act. Naomi's emptiness sets the stage for the fullness to come (cf. v21).</p>",
    "6": "<p><strong>vataqam hi vekhalloteha vatashav misedei moav</strong>: 'Then she arose with her daughters-in-law to return from the fields of Moab, for she had heard in Moab that YHWH had visited his people to give them bread.' The verb <em>qum</em> (to arise) followed by <em>shuv</em> (to return) is a classic departure formula, but <em>shuv</em> here carries dual weight: Naomi is returning home (geographic return) while the book also tracks a spiritual return. The impetus is <em>ki-paqad YHWH et-amo latet lahem lechem</em> — 'YHWH visited his people to give them bread.' The verb <em>paqad</em> (to visit, attend to, muster) is the God-of-Israel's signature action: the same word used for the Exodus visitation (Exod 4:31). The famine was YHWH's withdrawal; the provision is his return. Naomi's return is embedded in YHWH's return to his people.</p>",
    "7": "<p><strong>vatetzeh min hamakom asher hayetah sham</strong>: 'she set out from the place where she had been living.' <em>Hamakom</em> (the place) is used without naming Moab directly, creating a deliberate vagueness — the emphasis is on departure, not destination. The phrase <em>ve-shetei khalloteiha imah</em> (and her two daughters-in-law with her) positions the three widows as a fragile unit about to be dissolved. The word <em>derech</em> (road, way) appears — the three are on 'the way to the land of Judah' (<em>lashvot el-eretz yehudah</em>). Ruth is on a literal road and a theological one: a Moabite walking toward the covenant community.</p>",
    "9": "<p><strong>yiten YHWH lachem umenuchah ishah beit ishah</strong>: 'May YHWH grant each of you rest (<em>menucha</em>) in the house of her husband.' <em>Menucha</em> (rest, settlement, security) is the book's first stated goal for the women. The same word appears in 3:1 (<em>manoach</em> from the same root) when Naomi asks, 'shall I not seek security/rest for you?' The arc from Naomi's prayer (1:9) to her provision-seeking (3:1) is the structural spine of the book: the goal is <em>menucha</em>, covenant rest in a stable household, and the entire plot works to deliver it. Theologically, <em>menucha</em> anticipates the ultimate rest in YHWH himself (Ps 95:11; Heb 4:9-11).</p>",
    "10": "<p><strong>ki itach nashuv el-amech</strong>: 'No — we will return with you to your people.' The daughters-in-law initially resist Naomi's dismissal. The verb <em>shuv</em> (return) creates a paradox: returning with Naomi to Judah is described by the Moabite women as 'returning to your people' (<em>el-amech</em>). But Judah is not their people — it would be their people only through covenant adoption. This verse previews Ruth's ultimate declaration (v16): the loyalty she promises is an act of voluntary covenant embrace, not blood obligation.</p>",
    "11": "<p><strong>lamah telaknah imi ha-od li vanim beme'ai</strong>: 'Why would you come with me? Do I still have sons in my womb that they might be your husbands?' Naomi's rhetoric reveals her understanding of the levirate system: a widow's security came through marriage to a kinsman. Her point: even if she remarried tonight and bore sons, by the time they grew up the daughters-in-law would be too old. The <em>yibbum</em> (levirate marriage, Deut 25:5-10) underlying this speech also underlies the <em>goel</em> institution that drives the plot. Naomi uses levirate logic to release her daughters-in-law from obligation, not realizing that the <em>goel</em> institution will achieve what levirate cannot.</p>",
    "12": "<p><strong>shuvna velechna ki zaqanti mihyot le-ish</strong>: 'Go back, my daughters — I am too old to have a husband.' Naomi's triple imperative (<em>shuvna</em>) — go back, go back, go back — reinforces her attempt to release them from loyalty she considers burdensome. Her phrase <em>ki-zaqanti</em> (I am too old) acknowledges that her reproductive capacity is gone, and therefore the institutional pathways she knows (levirate, kinship marriage) are closed to her. This theological despair is what makes Boaz's action as <em>goel</em> so remarkable: it is not through Naomi's reproductive capacity but through the living Ruth that the line is preserved.</p>",
    "13": "<p><strong>lahen al-tenahena banot ki mar-li meod mikkem ki-yatzah bi yad-YHWH</strong>: 'Would you wait until they were grown? No, my daughters — my situation is bitterer for you than for me, for the hand of YHWH has gone out against me.' The phrase <em>yad YHWH</em> (hand of YHWH) describes divine agency in affliction — elsewhere it describes the plagues (Exod 9:3), battlefield defeat, and prophetic commissioning. Naomi's attribution of her suffering to YHWH's active agency is theologically significant: she does not accept random misfortune but acknowledges divine involvement. This is not the bitter fatalism it may seem but a form of faith: she is still addressing YHWH as the author of her circumstances, the same YHWH she later acknowledges as the one who 'has not abandoned <em>chesed</em> to the living and the dead' (2:20).</p>",
    "15": "<p><strong>hinneh shavah yevimtech el-amah ve'el-eloheiha shuvi acharei yevimtech</strong>: 'Look — your sister-in-law has gone back to her people and to her gods. Go back after your sister-in-law.' Naomi's instruction is remarkable: she explicitly mentions Orpah's return 'to her gods' (<em>eloheiha</em>), acknowledging that returning to Moab means returning to Chemosh/Moabite religion. By saying this to Ruth, Naomi is implicitly releasing Ruth from any obligation to YHWH she may have incidentally acquired through marriage. Ruth's subsequent declaration (v16) is therefore a counter to this explicit release — she chooses YHWH's people and YHWH's God despite being formally released from any obligation.</p>",
    "17": "<p><strong>baasher tamuti amut vesham ekaver</strong>: 'Where you die, I will die, and there I will be buried.' The burial commitment is the most radical element of Ruth's vow. In the ancient world, burial in one's ancestral land with one's people was a fundamental identity marker (Gen 23:1-20; 47:29-30; 50:24-25). Ruth voluntarily surrenders her ancestral burial place — her final resting place will be Naomi's, not Moab's. The oath formula <em>koh ya'aseh YHWH li vekhoh yosif</em> ('may YHWH do so to me and more also') is the strongest covenant oath formula in Hebrew, invoking YHWH as guarantor of the commitment. Ruth swears her personal devotion to Naomi by YHWH — a Moabite invoking Israel's God in a personal oath.</p>",
    "18": "<p><strong>vatere ki mitametzet hi lalechet ittah vattechdal ledabber eleiha</strong>: 'When Naomi saw that she was determined (<em>mitametzet</em>, from <em>ametz</em>, to be firm/strong) to go with her, she stopped urging her.' <em>Ametz</em> is the same root used for Joshua's commissioning: 'Be strong (<em>chazaq</em>) and courageous (<em>ametz</em>)' (Josh 1:6, 7, 9). The word applied to Ruth's resolution carries military/leadership-quality connotations — her commitment is not sentimental loyalty but firm resolve. Naomi's silence (<em>vattechdal ledabber</em>, she ceased speaking to her about it) is an eloquent concession: the argument is over, Ruth has won it through her own declaration.</p>",
    "19": "<p><strong>vatehem kol ha-ir aleihen</strong>: 'the whole city was stirred (<em>vatehem</em>) because of them.' The verb <em>hum/hamam</em> (to stir, be in tumult) is used of dramatic arrivals: the same root describes the city of Jerusalem 'in turmoil' at Jesus's entry in Matt 21:10 (LXX: <em>esesthe</em>). The women of Bethlehem ask: <em>hazot naomi</em>? 'Is this Naomi?' — a question charged with recognition and shock. The woman who left full is returning visibly reduced. The public recognition of her return and diminishment sets up her renaming speech in v20-21.</p>",
    "21": "<p><strong>ani mele'ah halachti verekam heshivani YHWH</strong>: 'I went out full (<em>mele'ah</em>) and YHWH has brought me back empty (<em>reqam</em>).' The <em>male'/req</em> (full/empty) polarity is this chapter's central contrast and the book's thesis statement in miniature. Naomi went out with husband and two sons — full household. She returns with nothing male. But the narrator knows — and the reader will learn — that Ruth, whom Naomi does not count as compensation, is worth 'more to you than seven sons' (4:15). YHWH's economy counts differently than Naomi's self-assessment. The emptiness she names is about to be filled through the very person she discounts. <strong>me ah te'anu li veYHWH anah vi veShaddai hera li</strong>: 'Why call me Naomi, when YHWH has testified against me, and Shaddai has brought calamity upon me?' — the two divine names used: <em>YHWH</em> (covenant God) and <em>Shaddai</em> (God Almighty, the name associated with patriarchal blessing and curse). The Shaddai name in the ancestral narratives is precisely the God who promises and blesses — Naomi applies the blessing-God in the mode of curse, a bitter reversal.</p>",
    "22": "<p><strong>veRut hamoa'viyah kallateha imah hashavah misedei moav</strong>: 'So Naomi came back, and with her Ruth the Moabitess, her daughter-in-law, who had returned from the fields of Moab.' The narrative closes the chapter by naming Ruth as 'the Moabitess' — her ethnic identity is foregrounded at each key moment (1:22; 2:2, 6, 21; 4:5, 10). The repetition is not accidental: the book is tracking a Moabite's incorporation into the covenant people, and the identifier reminds us of the boundary being crossed. <strong>vehemah ba'u bethlehem betechilat qetzir se'orim</strong>: 'and they arrived in Bethlehem at the beginning of the barley harvest.' The timing is narrative providence: the gleaning laws (Lev 19:9-10; Deut 24:19-22) were the legal institution that would provide for Ruth. YHWH times their arrival at the harvest's start — the legal provision for the poor is open.</p>"
  },
  "2": {
    "1": "<p><strong>ulnaomi meyuda levishah ish gibbor chayil mishpachat elimelech ushmo boaz</strong>: 'Now Naomi had a kinsman on her husband's side (<em>meyuda</em>, a known one), a man of standing (<em>gibbor chayil</em>) from the family of Elimelech. His name was Boaz.' The narrator introduces Boaz before Ruth meets him. <em>Gibbor chayil</em> (man of standing/valor/wealth) is the standard term for a man of means and social standing — the same phrase applied to Gideon (Judg 6:12), Jephthah (Judg 11:1), and later Kish (1 Sam 9:1). When Boaz later uses the feminine form (<em>eshet chayil</em>, woman of worth, 3:11) of Ruth, the verbal echo connects them: he is a man of worth, she is a woman of worth — a matched pair. The name <em>Boaz</em> may mean 'in him is strength' — a fitting name for the one who will act as goel.</p>",
    "4": "<p><strong>veyihineh boaz ba mibeit lechem vayyomer laqotzerim YHWH imachem</strong>: 'Just then Boaz arrived from Bethlehem and greeted the reapers: &ldquo;YHWH be with you.&rdquo; And they said: &ldquo;YHWH bless you.&rdquo;' Boaz's entrance is marked by the same providence-word <em>hinneh</em> (look! behold!) that marks divine appearances and significant arrivals throughout the OT. His greeting — <em>YHWH imachem</em> (YHWH be with you) — and the reapers' response — <em>yivarechcha YHWH</em> (YHWH bless you) — establish the field as a space of covenant blessing. Boaz speaks YHWH's name twice in greeting before any action occurs. This is not incidental piety but characterization: this is a man whose daily speech is saturated with covenant awareness.</p>",
    "5": "<p><strong>vayyomer boaz lena'aro hannitzav al-haqotzerim lemi hana'arah hazot</strong>: 'Boaz asked his servant who was in charge of the reapers: &ldquo;Whose young woman is this?&rdquo;' The question <em>lemi hana'arah</em> (to whom does this young woman belong?) reflects the social structure: a woman gleaning alone was typically attached to a household. Boaz's noticing of Ruth begins the plot's central movement. The <em>na'ar</em> (servant/lad) in charge of the reapers — an overseer — will convey Boaz's instructions and Boaz's character to the reader through his report about Ruth (v6-7).</p>",
    "6": "<p><strong>vaya'an hana'ar hannitzav al-haqotzerim vayyomer na'arah mo'aviyah hi hashavah im naomi misedei moav</strong>: 'The foreman answered: &ldquo;She is the Moabite young woman who returned with Naomi from Moab.&rdquo;' The first thing said about Ruth to Boaz is her Moabite identity. The foreman's accurate identification — she is <em>na'arah mo'aviyah</em> (the Moabite young woman) — is the social and ethnic fact that makes Ruth's subsequent treatment by Boaz all the more remarkable. Boaz will show favor to someone his culture had reason to exclude. The ethnic designation is not the narrator's prejudice but a setup for the reversal of expected social behavior.</p>",
    "7": "<p><strong>vatomer elaqqetah-na veasafti va'omerim achar haqotzerim</strong>: 'She asked: &ldquo;Please let me glean and gather among the sheaves after the reapers.&rdquo;' Ruth's request uses the particle of entreaty <em>na</em> (please) — she is asking permission, not asserting a right. Her request goes beyond the standard gleaning (picking up what falls) to gleaning 'among the sheaves' (<em>ve-asafti va-omerim</em>) — a more aggressive form. The narrator adds: <em>vatavo vata'amod meaz haboker ve'ad attah zeh shivtah habayit me'at</em> — 'she came, and has been standing from early morning until now, except that she sat in the house a little.' Ruth's diligence is established: she arrived early, worked continuously, and her only break was minimal rest. Her work ethic reinforces her character.</p>",
    "8": "<p><strong>halo shamaat biti al-telchi liqlot besadeh acher</strong>: 'Listen carefully, my daughter. Do not go to glean in another field.' Boaz's address <em>biti</em> (my daughter) establishes a protective, familial register — he is an older kinsman speaking with paternal authority and warmth, not merely an employer to an employee. His prohibition 'do not go to another field' is a guarantee of provision: he is taking on responsibility for her welfare. The phrase <em>vekhen tigdavein el-na'arotai</em> (stay close to my young women) provides the mechanism: Ruth is to be integrated into Boaz's household workforce, no longer gleaning as an independent poor woman but as someone under his protection.</p>",
    "9": "<p><strong>einayich basadeh asher-yiqtzoru vehalachti achareihen</strong>: 'Watch the field where they are reaping and follow along after them.' Boaz provides Ruth a practical strategy for safe gleaning: staying in the visible, supervised area of his field, following his own workers. <strong>halo tzivieti et-hane'arim levilthi nege'a bach</strong>: 'I have commanded the young men not to touch you.' The prohibition here is against <em>naga</em> (to touch/harm) — Boaz explicitly protects Ruth from male harassment, a real danger for a lone foreign woman gleaning. His protection addresses a vulnerability Ruth herself named to Naomi later (v22: stay with his workers so 'they do not fall upon you in another field'). <strong>vetzamit valacht el-hakkeilim veshatit mimme asher yishavun hana'arim</strong>: 'and when you are thirsty, go to the vessels and drink what the young men have drawn.' Even water — normally a significant provision in a dry-season harvest — Boaz provides proactively.</p>",
    "10": "<p><strong>vatippol al-paneiha vatishtachu artzah vatomer elav madua matzati chen be'einecha lehakkireini ve'anochi nokhriyvah</strong>: 'She fell with her face to the ground and bowed, and said to him: &ldquo;Why have I found favor (<em>chen</em>) in your sight, to the point of noticing me — and I am a foreigner (<em>nokhriyvah</em>)?&rdquo;' Ruth's prostration is the full covenant-reverence gesture. Her rhetorical question expresses genuine astonishment: <em>chen</em> (favor, grace) is not what a foreign gleaner expected. The word <em>nokhriyvah</em> (foreigner, stranger) — more distant than <em>ger</em> (sojourner) — marks Ruth as culturally outside the covenant community. Her own self-designation heightens the contrast with Boaz's generosity. He will shortly resolve the tension between her foreign status and his response to her: her <em>chesed</em> to Naomi is the reason (v11).</p>",
    "11": "<p><strong>vayya'an boaz vayyomer lah hugad hugad li kol asher asit et chamotekh</strong>: 'Boaz answered her: &ldquo;All that you have done for your mother-in-law has been fully reported to me.&rdquo;' The infinitive absolute <em>hugad hugad</em> (lit. 'it has been told, told' = it has been fully reported) emphasizes the completeness of his information. Boaz knows everything: the abandonment of her home country and her father's household, and the commitment to a mother-in-law in her grief. <strong>va-telchi el-am asher lo-yada'at tmol shilshom</strong>: 'and that you have come to a people you did not know before.' The phrase <em>lo-yada'at tmol shilshom</em> (you did not know before) underscores the radical nature of Ruth's commitment: she came to a complete stranger people. This is precisely the Abrahamic paradigm — leaving the known for the covenant people (Gen 12:1).</p>",
    "13": "<p><strong>vatomer emtzah-chen be'einecha adoni ki nichhamtani vechi dibbarta al-lev shiphchatecha</strong>: 'She said: &ldquo;May I continue to find favor in your sight, my lord — for you have comforted me (<em>nichhamtani</em>) and spoken to the heart (<em>dibbarta al-lev</em>) of your maidservant.&rdquo;' <em>Nichham</em> (to comfort) is the verb of prophetic comfort: YHWH comforts his people (<em>nachem nachem ammi</em>, Isa 40:1). Ruth's use of this word for Boaz's treatment of her builds the latent typology: Boaz as image of YHWH's comforting concern for the outcast and bereaved. <em>Dibbarta al-lev</em> (speak to the heart) is an idiom of deep emotional reassurance (Gen 34:3; 50:21; Judg 19:3; Isa 40:2; Hos 2:16). <strong>ve-anochi lo ehyeh kechachat shifchotecha</strong>: 'although I am not even as one of your maidservants' — Ruth's continued self-diminishment in the face of Boaz's kindness, which she regards as exceeding her station.</p>",
    "14": "<p><strong>vayyomer lah boaz le'et ha-ochel geshi halom ve'achalt min-halechem</strong>: 'At mealtime Boaz said to her: &ldquo;Come here and eat some bread.&rdquo;' The invitation to eat at Boaz's table is social inclusion: Ruth is invited to the inner circle of workers who eat with the owner. <strong>vatetaleh hemtzaltah vatochal vatisba vattothar</strong>: 'she dipped her morsel in the vinegar, and sat beside the reapers, and he passed to her parched grain (<em>qali</em>), and she ate until she was satisfied (<em>vatisba</em>) and had some left over (<em>vatothar</em>).' The progression — <em>satiation and surplus</em> — answers Naomi's self-description in v21: 'YHWH has brought me back empty (<em>reqam</em>).' Naomi said 'empty'; the narrator shows Ruth eating to satiation and having leftovers to bring home. The reversal begins with Boaz's table.</p>",
    "15": "<p><strong>vataqam lilaqqet vayetzav boaz et-ne'arav lemor gam bein ha-omerim telaqqet</strong>: 'When she rose to glean again, Boaz commanded his young men: &ldquo;Let her glean even among the sheaves.&rdquo;' Boaz's command goes beyond his initial permission: she may glean <em>bein ha-omerim</em> (among the sheaves), not merely in the perimeter where fallen grain lies. This is direct intervention on her behalf, exceeding legal obligation. The gleaning laws required leaving the edges and fallen grain; Boaz gives Ruth access to the harvested portion itself. <strong>velo techferu otah</strong>: 'and do not rebuke her' — the young men are explicitly told not to embarrass or shame her for gleaning in the harvested area. Boaz removes every obstacle to Ruth's provision.</p>",
    "16": "<p><strong>vegam shol tashollu lah min hatzevutim</strong>: 'pull out some stalks from the bundles and drop them deliberately for her.' <em>Shol tashollu</em> (pull out, you shall pull out) — another infinitive absolute for emphasis. The instruction is to create artificial abundance for Ruth: the workers are to create 'falls' that look accidental but are engineered by Boaz's command. This is provision beyond gleaning law, done covertly — Ruth will think her gleaning is productive when in fact the abundance is Boaz's gift. The hiddenness of the grace is part of its character: Boaz does not make Ruth dependent on public charity but dignifies her labor while covertly multiplying its fruit. This is a model for <em>chesed</em>: generous beyond obligation, protecting the dignity of the recipient.</p>",
    "17": "<p><strong>vatilaqqet basadeh ad ha'erev vatachbot et asher liqqetah vayehi ke'efah se'orim</strong>: 'So she gleaned in the field until evening. When she beat out what she had gleaned, it came to about an ephah of barley.' An ephah of barley is approximately 22 liters — far more than a typical day's gleaning. The surplus is the fruit of Boaz's hidden providence (v16). The vast quantity will strike Naomi as unusual (v19: 'Where did you glean today?') and trigger the revelation of Boaz's identity. Abundance is the sign by which Naomi will recognize YHWH's hand through his human agent.</p>",
    "18": "<p><strong>vatissa vatavo hair vatare chamotah et asher liqqetah</strong>: 'She took it up and went into the town. Her mother-in-law saw what she had gleaned.' The verb <em>vatissa</em> (she lifted up, carried) describes Ruth carrying the substantial ephah of grain into Bethlehem — a visible sign of the day's provision. The domestic scene: Ruth shows Naomi what she gleaned, then gives her the leftover meal from Boaz's table. The detail that Ruth 'also gave her what she had left over after being satisfied' (<em>vatotzieh vatitenen lah et asher hotarah miseba'ah</em>) doubles the provision: not only an ephah of grain but also the portion from Boaz's own meal. The day of gleaning has become a day of abundance.</p>",
    "19": "<p><strong>vatomer lah chamotah eifo liqqatat hayom ve'anah asit baruch makkirech</strong>: 'Her mother-in-law asked her: &ldquo;Where did you glean today? Where did you work? Blessed be the one who noticed you!&rdquo;' Naomi's question follows the surplus logic: the quantity of grain demands an explanation. <em>Baruch makkirech</em> (blessed be the one who took notice of you) is a blessing spoken before the name is known — Naomi intuitively recognizes divine providence in the abundance before she knows its instrument. The blessing is fulfilled when Boaz speaks the same <em>baruk</em> form over Ruth (3:10). The chain of blessing connects the human agents to the divine source.</p>",
    "21": "<p><strong>vatomer Rut hamoa'viyah gam ki amar elay im-hane'arim asher-li tidbaqin ad im-killu et kol-haqatzir asher-li</strong>: 'Ruth the Moabitess added: &ldquo;He also told me: Stay close to my workers until they have finished all my harvest.&rdquo;' Ruth quotes Boaz's instruction with the Hebrew form <em>tidebeqin</em> (stay/cleave close) — the same root (<em>dbq</em>) used for Ruth's own clinging to Naomi in v14: 'she clung (<em>davqah</em>) to her.' Ruth's attachment to Naomi and Boaz's instruction to cleave to his workers both use the <em>dbq</em> covenant-loyalty word — the word of marital bond (Gen 2:24) and covenant faithfulness applied to field-working. The entire plot is a network of <em>dbq</em> loyalties.</p>",
    "22": "<p><strong>vatomer naomi el-Rut kallateha tov biti ki tetze'i im-na'arotav velo yifge'u bach besadeh acher</strong>: 'Naomi said to Ruth her daughter-in-law: &ldquo;It is good, my daughter, that you go out with his young women, so they do not fall upon you in another field.&rdquo;' <em>Yifge'u bach</em> (they fall upon you, meet you with hostile intent, harm you) — <em>paga</em> is often a violent encounter word. Naomi understands the social danger Ruth faces as a foreign woman gleaning alone. Boaz's field is protective space; another field could be dangerous. Naomi's advice is practical wisdom based on social reality, but it also functions theologically: she is directing Ruth to stay within the protective sphere of the <em>goel</em>, not knowing yet that Boaz is more than a field-owner.</p>",
    "23": "<p><strong>vatidbeq bene'arot boaz lilaqqet ad-kelot qetzir hase'orim viqetzir hachittim vateshev et-chamotah</strong>: 'So Ruth stayed close to the young women of Boaz and gleaned through the end of the barley harvest and the wheat harvest. And she lived with her mother-in-law.' The summary verse spans the entire harvest season: barley (March-April) followed by wheat (May-June) — about seven weeks, the period between Passover and Shavuot (Pentecost). Ruth's faithful gleaning throughout the entire harvest season shows sustained loyal labor. <em>Vateshev et-chamotah</em> (she lived with her mother-in-law) is not merely domestic information but a measure of loyalty: through both harvests she stayed with Naomi rather than pursuing other opportunities. Her constancy matches her ch1 declaration.</p>"
  },
  "3": {
    "1": "<p><strong>vatomer lah naomi chamotah biti halo avaqesh lach manoach asher yitav lach</strong>: 'Then Naomi her mother-in-law said to her: &ldquo;My daughter, shall I not seek rest (<em>manoach</em>) for you, that it may go well with you?&rdquo;' <em>Manoach</em> (resting place, security) is from the same root as <em>menucha</em> in v9 of ch1 — Naomi's original prayer for the daughters-in-law (<em>yiten YHWH lachem menucha</em>) is now being answered through Naomi's own initiative. The structural echo is intentional: what Naomi prayed God would grant, she is now working to achieve, having recognized Boaz as the instrument. Prayer and human action collaborate; providence works through means.</p>",
    "2": "<p><strong>veatah halo boaz meyuda'tenu asher hayit et-ne'arotav hineh hu zorea et-goren hase'orim halaylah</strong>: 'Now is not Boaz — our kinsman — with whose young women you have been? He is winnowing barley at the threshing floor tonight.' <em>Meyuda'tenu</em> (our known one, our kinsman) — Naomi uses the intimate kinship term, indicating the relationship that makes the plan possible. The <em>goren</em> (threshing floor) is a liminal space: the harvest boundary between agricultural labor and celebration. Winnowing at night, when the evening breeze came up, was standard practice. The threshing floor scene that follows takes place in this in-between space — harvest done but new life not yet established — between the old economy and the new.</p>",
    "3": "<p><strong>verachatz vesakht vesamet simalotayich uyaradt hagoren</strong>: 'Wash yourself, put on fragrant oil, dress yourself in your best garment, and go down to the threshing floor.' Naomi's instructions have a deliberate sequence: washing, anointing (<em>sukh</em>, anoint with oil — a restoration act associated with the end of mourning, 2 Sam 12:20), and dressing in one's 'garment' (best clothes). These are precisely the acts Ruth would have suspended during her widow's mourning. Naomi is instructing Ruth to resume the posture of an eligible woman. The scene is careful to avoid explicit sexual framing: Ruth is presenting herself as available for redemption, not for seduction. <strong>al-tivad'i la-ish ad kaloto le'echol velishhot</strong>: 'Do not make yourself known to the man until he has finished eating and drinking.' Wait for the right moment — a social wisdom instruction that also ensures Boaz is in a relaxed, receptive state.</p>",
    "4": "<p><strong>vihi veshochvo veyada'at et hamakom asher yishkav-sham uba'at vegilleit marge'lotav ushachavt</strong>: 'When he lies down, take note of the place where he lies. Then go, uncover his feet, and lie down.' <em>Margelot</em> (feet, the place of the feet) — Ruth is to lie at his feet, the posture of a supplicant before a lord or a kinsman approaching a superior. The uncovering of the feet is a gesture loaded with symbolism: in ANE practice, uncovering the feet of a sleeping man was a way of indicating a claim. Ruth's action requests coverage — she will explicitly ask Boaz to spread his <em>kanaf</em> (wing/skirt) over her (v9). The two gestures — uncovering his feet, requesting he cover her — form the claim ritual. <strong>vehu yaggid lach et asher ta'asi</strong>: 'he will tell you what to do' — Naomi trusts Boaz to respond correctly once the situation is created.</p>",
    "5": "<p><strong>vatomer eleiha kol asher tomri elai e'eseh</strong>: 'Ruth said to her: &ldquo;I will do everything you say.&rdquo;' Ruth's obedience to Naomi continues the pattern of her initial declaration (1:16-17). Her words here echo the Israelite covenant formula from Sinai: <em>kol asher dibber YHWH na'aseh</em> (all that YHWH has spoken we will do, Exod 19:8; 24:3). Ruth's total submission to Naomi's instruction is narrated without comment — but the reader familiar with covenant language recognizes the formula of complete loyalty being applied to human relationship.</p>",
    "6": "<p><strong>vatired hagoren vattas kechol asher tzivatah chamotah</strong>: 'So she went down to the threshing floor and did everything her mother-in-law had instructed her.' The narrative economy is notable: everything Naomi said is executed without modification or deviation. Ruth's obedience is absolute and un-editorialized. The threshing floor is now the stage for the book's turning point — all the preceding scenes (the gleaning, the meals, the kinship identifications) have been preparatory. The legal and covenantal action now takes place at night, at the liminal boundary of harvest completion.</p>",
    "7": "<p><strong>vayochal boaz vayesht vayitav libo vayavo lishkav biqtzeh ha'arema</strong>: 'When Boaz had eaten and drunk and his heart was glad (<em>vayitav libo</em>), he went and lay down at the far end of the grain heap.' <em>Vayitav libo</em> (his heart was good/glad) is a contentment phrase used throughout the OT (Judg 16:25; 19:6; 1 Sam 25:36). Boaz is relaxed, the harvest is done, the season's work complete — he has no reason to expect what is about to happen. <strong>vatavo valat vategel margelotav vatishkav</strong>: 'she came quietly, uncovered his feet, and lay down.' The adverb <em>valat</em> (quietly, stealthily) marks the approach as deliberate and planned. Ruth executes Naomi's instructions precisely.</p>",
    "8": "<p><strong>vayehi bachatzi hallaylah vayecherad ha-ish vayyilafet vehinneh ishah shochebet margelotav</strong>: 'At midnight the man was startled (<em>vayecherad</em>), turned himself (<em>vayyilafet</em>), and — look! a woman was lying at his feet.' <em>Vayecherad</em> (he trembled/was startled) describes the physical shock of waking to an unexpected presence. <em>Vayyilafet</em> (turned himself, twisted around) — an unusual verb, possibly describing the grasping motion of someone waking to something underfoot. The word <em>hinneh</em> (behold! look!) marks Boaz's moment of perception as a significant discovery. The entire scene is handled with narrative restraint: nothing happens beyond the stated facts, and the narrator refuses to fill in what might have occurred in the night between midnight and morning (v14).</p>",
    "11": "<p><strong>ve'atah biti al-tire'i kol asher tomri elai e'eseh-lach ki yoda'a kol sha'ar ami ki eshet chayil at</strong>: 'And now, my daughter, do not be afraid. I will do for you everything you have asked, for all the gate of my people knows that you are a woman of worth (<em>eshet chayil</em>).' <em>Eshet chayil</em> (woman of valor/worth) is the feminine form of <em>gibbor chayil</em> used of Boaz in 2:1. The narrator has been building to this designation: Ruth's gleaning diligence, her loyalty to Naomi, her restraint at the threshing floor — all constitute the <em>chayil</em> that the town's testimony confirms. Boaz's statement that 'all the gate knows' is significant: the gate is the legal assembly. Ruth's reputation has preceded any formal proceedings. The <em>eshet chayil</em> designation also echoes the closing poem of Proverbs (31:10-31), which begins <em>eshet chayil mi yimtza</em> (a woman of worth, who can find?) — Ruth is the narrative embodiment of that figure.</p>",
    "13": "<p><strong>lini halaylah vehayah vaboqer im-yig'alech tov yig'al ve'im-lo yachpotz lig'olach gealticha anochi</strong>: 'Stay here tonight. In the morning — if he is willing to act as kinsman-redeemer for you, good, let him do it. But if he is not willing, as YHWH lives, I will redeem you.' The oath <em>chay YHWH</em> (as YHWH lives) is the strongest form of personal guarantee in biblical Hebrew — Boaz invokes YHWH's own life as the surety of his promise. His willingness to redeem is now bound by covenant oath. The nearer kinsman will refuse; Boaz will fulfill. <em>Shichvi ad-haboqer</em>: 'lie down until morning' — the night is protected, proper, and unscandalous; Boaz himself ensures Ruth's departure before she can be recognized (v14).</p>",
    "14": "<p><strong>vatishkav margelotav ad haboqer vataqom biterem yakir ish et re'ehu</strong>: 'So she lay at his feet until morning. She rose before anyone could recognize another, for he said: &ldquo;Let it not be known that a woman came to the threshing floor.&rdquo;' Boaz's care for Ruth's reputation is active: he explicitly instructs that her presence be undisclosed. His reason is protective of Ruth, not of himself. The threshing floor at night was not a scandal-free location in Israelite social memory (cf. Hos 9:1); Boaz takes no chances with Ruth's honor. The detail that 'she rose before anyone could recognize another' (<em>biterem yakir ish et re'ehu</em>) indicates pre-dawn darkness — the night has been honorable throughout, and Boaz ensures the morning will not suggest otherwise.</p>",
    "15": "<p><strong>vayyomer havi hamitpahat asher alayich ve'itzeti-bah vatochel shesh midot se'orim</strong>: 'He also said: &ldquo;Bring the cloak you are wearing and hold it out.&rdquo; She held it out, and he measured six measures of barley into it.' Six measures of barley is a significant gift — large enough to burden Ruth for the walk home, conspicuous enough that Naomi will ask about it. The quantity may be deliberate: six units suggest work, while seven suggests completeness (cf. the six days of harvest labor and the seventh of rest). Boaz sends Ruth away laden, not empty-handed — a direct response to Naomi's complaint that YHWH brought her back 'empty' (1:21). Each gift from Boaz is an anti-emptiness act.</p>",
    "16": "<p><strong>vatavo el-chamotah vatomer mi at bitti vataged lah et kol asher asah lah ha-ish</strong>: 'When she came to her mother-in-law, Naomi asked: &ldquo;Who are you, my daughter?&rdquo; And she told her all that the man had done for her.' The question <em>mi at</em> (who are you?) has been read as recognition — 'who are you, now?' — asking whether Ruth has been transformed by the night's encounter. Ruth is not yet a wife, but she is no longer merely Naomi's Moabite companion. She is now a woman under the formal protective commitment of a <em>goel</em>. The answer to Naomi's question will unfold in ch4.</p>",
    "17": "<p><strong>vatomer shesh hase'orim ha'elle natan li ki amar elai al-tavo reqam el-chamotach</strong>: 'She added: &ldquo;He gave me these six measures of barley, with the instruction not to go back empty-handed (<em>reqam</em>) to your mother-in-law.&rdquo;' The word <em>reqam</em> (empty) directly echoes Naomi's lament in 1:21: 'YHWH has brought me back empty (<em>reqam</em>).' Boaz explicitly refuses to send Ruth back empty-handed to Naomi — his gift is targeted at reversing Naomi's stated emptiness. Whether or not Naomi understood the echoed word, the narrator and the reader do: the man who says 'not empty' is answering YHWH's supposed abandonment of Naomi.</p>",
    "18": "<p><strong>vatomer shevi biti ad asher tede'i eich yippol davar ki lo yishqot ha-ish ki-im killah hadavar hayom</strong>: 'Then Naomi said: &ldquo;Stay still, my daughter, until you know how the matter will turn out. The man will not rest unless he settles the matter today.&rdquo;' Naomi's confidence in Boaz is complete: <em>ki lo yishqot ha-ish ki-im killah hadavar</em> (the man will not rest/be quiet unless he has completed the matter). <em>Shaqat</em> (to rest, be quiet, settle) echoes the <em>manoach/menucha</em> (rest) theme — Boaz will not find his own rest until he has secured Ruth's rest. The one who gives rest is himself driven by the need to give it. Naomi's instruction to Ruth — 'stay still' (<em>shevi</em>) — suspends Ruth's agency while the legal mechanism works. The waiting is itself an act of trust.</p>"
  },
  "4": {
    "2": "<p><strong>vayyiqqach asarah anashim miziqnei ha-ir vayyomer shevu-poh vayeshvu</strong>: 'Then Boaz took ten of the elders of the town and said: &ldquo;Sit down here.&rdquo; They sat down.' The ten elders constitute a legal quorum for the formal proceedings. In later Jewish law, a minyan of ten is required for communal worship and certain legal acts — this scene is one of the textual anchors for that tradition. Boaz's action at the gate is methodical: he arrived, waited for the nearer kinsman (v1), gathered witnesses, and convened the proceeding before Ruth's potential redemption is named. He controls the legal process to ensure the outcome.</p>",
    "3": "<p><strong>vayyomer lagg'el cheleqat hasadeh asher le'achinu le-elimelech machar naomi hashavah misedeh moav</strong>: 'He said to the kinsman: &ldquo;Naomi, who has returned from Moab, is selling the piece of land that belonged to our kinsman Elimelech.&rdquo;' Boaz introduces the land transaction first, before Ruth is mentioned. This sequencing is deliberate: the nearer kinsman agrees to redeem the land (v4), presumably calculating the financial benefit of adding land to his holdings. Only after the kinsman agrees does Boaz spring the full obligation (v5) — Ruth comes with the land. The legal strategy is careful: Boaz presents the terms in stages to ensure the nearer kinsman's own refusal.</p>",
    "4": "<p><strong>va'ani amarti e'elah oznecha lemor qeneh neged hayoshvim</strong>: 'I thought I should inform you, saying: Buy it before those sitting here.' Boaz's obligation to inform the nearer kinsman first is the <em>goel</em> protocol in action: the closest kinsman has first right of redemption. <em>Ge'al-lach ata</em> (redeem it yourself) — Boaz gives the nearer kinsman the right of first refusal in proper legal sequence. <strong>ve'im lo yig'al haggedah-li ve'edah ki ein zulatecha lig'ol va'anochi acharecha</strong>: 'And if you will not redeem it, tell me, so that I may know. For there is no one other than you to redeem it, and I come after you.' Boaz transparently discloses both the priority order and his own position in it — he is not hiding his interest.</p>",
    "8": "<p><strong>vayyomer hagg'el leBoaz qeneh-lach vayyishlof na'alo</strong>: 'So the kinsman said to Boaz: &ldquo;Buy it for yourself.&rdquo; And he drew off his sandal.' The sandal ceremony (<em>shalaf na'alo</em>) formalizes the transfer of redemption rights. Deut 25:9-10 describes a related but different ceremony (the widow pulling off the refusing brother's sandal as an act of shame in the levirate refusal). Here the kinsman himself removes his own sandal and gives it to Boaz — not a shame ceremony but a voluntary transfer of rights. Ruth 4:7 explains this was the custom to 'confirm all matters in Israel.' The symbolic logic: the foot that walked the land is released; Boaz's foot will now walk it.</p>",
    "9": "<p><strong>vayyomer boaz lazeqenim vekhol ha'am edim atem hayom ki qaniti et-kol-asher le-elimelech</strong>: 'Then Boaz said to the elders and all the people: &ldquo;You are witnesses today that I have purchased all that belonged to Elimelech.&rdquo;' <em>Edim atem hayom</em> (you are witnesses today) — the formulaic witness declaration before the assembled gate. Boaz names all the property transferred: Elimelech's land, plus what belonged to Chilion and Mahlon. This is the comprehensive kinsman-redemption (<em>ge'ulah</em>) of the full family estate — land, name, and legacy.</p>",
    "11": "<p><strong>vayyomru kol ha'am asher bassha'ar vehazeqenim edim yiten YHWH et-ha'isha haba'ah el-beitcha kerache'l ukhele'ah asher banu sheteihen et beit Yisrael</strong>: 'All the people who were at the gate and the elders said: &ldquo;We are witnesses. May YHWH make the woman who is coming into your house like Rachel and Leah, who together built the house of Israel.&rdquo;' The communal blessing invokes the matriarchs Rachel and Leah — the Moabite Ruth is blessed to be like the founding mothers of Israel. The boundary between insider and outsider is dissolved by covenant incorporation: a Moabite is now prayed over using the names of Israel's greatest matriarchs. <strong>ase chayil be-efratah uqera shem beveit lechem</strong>: 'may you act worthily (<em>ase chayil</em>) in Ephrathah and call forth a name (<em>uqera shem</em>) in Bethlehem' — Boaz is exhorted in the same <em>chayil</em> vocabulary used of both him (2:1) and Ruth (3:11).</p>",
    "12": "<p><strong>uveithcha yihyeh keveit perets asher yaldah tamar leyehudah min-hazera asher yitten YHWH lecha min-hana'arah hazot</strong>: 'And may your house be like the house of Perez, whom Tamar bore to Judah — from the offspring that YHWH will give you from this young woman.' The Perez-Tamar allusion is significant: Tamar (a woman of ambiguous ethnic status who used a provocative encounter to secure her levirate rights from Judah) is Ruth's exact narrative parallel. Both women took bold action to secure their place in the covenant line when the men responsible for them failed. The Perez lineage is already the line from which Boaz descends (v18-22 — the closing genealogy begins with Perez). The witnesses' blessing links the current story backward to its most exact prototype.</p>",
    "13": "<p><strong>vayyiqqach boaz et-rut vatehi lo le'isha vayavo eleiha vayitten YHWH lah herayon vatteled ben</strong>: 'So Boaz took Ruth, and she became his wife. When he went in to her, YHWH granted her conception, and she bore a son.' The birth of the son is YHWH's direct act: <em>vayitten YHWH lah herayon</em> (YHWH granted her conception). Ruth's previous barrenness (she had been married ten years to Mahlon without children, 1:4-5) is resolved by divine gift. The son is not primarily Boaz and Ruth's son but Naomi's restoration: the women of the neighborhood will name him for Naomi (v17). YHWH's providence, worked through human <em>chesed</em>, is complete.</p>",
    "14": "<p><strong>vatomerena hanashim el-naomi baruch YHWH asher lo hishbit lach go'el hayom</strong>: 'The women said to Naomi: &ldquo;Blessed be YHWH who has not left you this day without a kinsman-redeemer (<em>go'el</em>).&rdquo;' The women's doxology names the newborn Obed as a <em>go'el</em> — a kinsman-redeemer. The <em>goel</em> arc has moved: Boaz was the redemptive agent, now Obed is the living fulfillment of what the redemption secured. The <em>goel</em> terminology applied to an infant echoes the messianic trajectory: the redeemer begins as a child. <strong>veyiqara shemo beyisrael</strong>: 'may his name be called forth in Israel' — anticipating his famous grandson David.</p>",
    "15": "<p><strong>vehayah lach lemeshiv nefesh ulekhalkkel et-sevvatecha ki challateach asher ahavattecha yeladathu</strong>: 'He will restore your life (<em>lemeshiv nefesh</em>) and sustain you in your old age, for your daughter-in-law who loves you, who is more to you than seven sons, bore him.' <em>Meshiv nefesh</em> (restorer of life/soul) is applied to Obed, but through Ruth. The phrase <em>asher ahavattecha</em> (who loves you) — Ruth's love for Naomi is the theological engine of the entire book. It is the love of Ruth (<em>chesed</em> enacted as <em>ahavah</em>) that drives every plot movement. The extraordinary claim — Ruth is 'better than seven sons' to you — inverts the patriarchal calculus that had made sons the supreme value. Ruth's <em>chesed</em> exceeds the most valued thing in her cultural world.</p>",
    "16": "<p><strong>vatikach naomi et-hayeled vatashehu vecheiqah vatehi lo le-omenet</strong>: 'Naomi took the child and laid him against her chest (<em>vecheiqah</em>) and became his nurse.' <em>Cheiq</em> (chest/lap/bosom) is the intimate holding space — the same word used for Moses's mother holding him (Exod 4:6) and for the servant of the poor man holding his ewe lamb (2 Sam 12:3). Naomi, who described herself as 'empty' (1:21) and unable to provide sons (1:11-12), holds the child as if he were her own son — because through the <em>goel</em> transaction, he legally preserves Elimelech's name (v10). The empty has been filled; the bitter has become sweet — the book completes the reversal it began with Naomi's self-renaming.</p>",
    "19": "<p><strong>vechetzron holid et-ram veram holid et-amminadav</strong>: 'Hezron fathered Ram, and Ram fathered Amminadab.' The genealogy descends through Hezron (son of Perez, son of Judah, son of Jacob) — these are the tribal ancestors of the Davidic line. Hezron appears in the genealogy of Num 26:21 and 1 Chr 2:9-10. Ram is the father of Amminadab, whose daughter Elisheba became Aaron's wife (Exod 6:23) — a point linking this genealogy to the priestly line as well as the royal line. The ten-generation list (vv18-22) spanning Perez to David maps the chosen lineage through the Bethlehem clan.</p>",
    "20": "<p><strong>ve'amminadav holid et-nachshon venachshon holid et-salmah</strong>: 'Amminadab fathered Nahshon, and Nahshon fathered Salmon.' <em>Nachshon</em> (Nahshon son of Amminadab) was the chieftain of the tribe of Judah in the wilderness (Num 1:7; 2:3; 7:12) and the first to cross the Red Sea according to one tradition. His prominence in the wilderness generation connects the Ruth genealogy to the Exodus era. <em>Salmah/Salmon</em> is likely the father of Boaz who took Rahab as wife (see Matt 1:5 — 'Salmon the father of Boaz by Rahab'), another foreign woman in the Davidic lineage. The genealogy preserves the memory of foreign-woman inclusion: Tamar, Rahab, Ruth — all non-Israelites incorporated into the line that leads to David and ultimately to Christ.</p>",
    "21": "<p><strong>vesalmah holid et-boaz uvoaz holid et-oved</strong>: 'Salmon fathered Boaz, and Boaz fathered Obed.' The names now carry the full weight of the narrative. <em>Boaz</em> — whom we have known for the entire book as the <em>gibbor chayil</em>, the redeemer, the one who spoke blessing and performed <em>chesed</em> — appears here as a link in a chain: not merely a character but a hinge in the genealogy of salvation. <em>Obed</em> — whose name means 'servant/worshiper' — is the son born from the <em>goel</em> transaction, the one who fills Naomi's empty arms and preserves Elimelech's name.</p>",
    "22": "<p><strong>ve'oved holid et-yishai veyishai holid et-david</strong>: 'Obed fathered Jesse, and Jesse fathered David.' The final verse of Ruth is the book's destination: <em>David</em>. The entire narrative — the famine, the Moabite marriage, the three deaths, Naomi's emptiness, Ruth's loyalty, Boaz's redemption, Obed's birth — has been moving toward this name. Ruth's Christological significance begins here: Matt 1:5 includes her in the genealogy of Jesus ('Boaz the father of Obed by Ruth, and Obed the father of Jesse, and Jesse the father of David the king'). The Moabite woman who chose <em>chesed</em> and YHWH's people over her own becomes the great-grandmother of Israel's greatest king and an ancestor of the Messiah. The boundary-crossing she enacted in ch1 — leaving her gods, her people, her homeland — is the same boundary-crossing that the gospel enacts: bringing those far off into the covenant community.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'ruth')
    merge_comm(existing, RUTH)
    save_comm('mkt-original', 'ruth', existing)
    added = sum(len(vv) for vv in RUTH.values())
    print(f'ruth mkt-original: added up to {added} verses across ch1-4')

if __name__ == '__main__':
    main()
